2: const errors = require('@tryghost/errors');
3: const nql = require('@tryghost/nql');
4: const {splitFilter} = require('@tryghost/mongo-utils');
5: 
6: /**
7:  * @typedef {import('@tryghost/api-framework').Frame} Frame
8:  */
9: 
10: const {MethodNotAllowedError} = require('@tryghost/errors');
11: const tpl = require('@tryghost/tpl');
12: 
13: const messages = {
14:     cannotDestroyComments: 'You cannot destroy comments.',
15:     memberNotFound: 'Unable to find member'
16: };
17: 
18: module.exports = class CommentsController {
19:     /**
20:      * @param {import('./comments-service')} service
21:      * @param {import('./comments-stats-service')} stats
22:      */
23:     constructor(service, stats) {
24:         this.service = service;
25:         this.stats = stats;
26:     }
27: 
28:     async #setImpersonationContext(options) {
29:         if (options.impersonate_member_uuid) {
30:             options.context = options.context || {};
31:             options.context.member = options.context.member || {};
32:             options.context.member.id = await this.service.getMemberIdByUUID(options.impersonate_member_uuid);
33:         }
34:     }
35: 
36:     #checkMember(frame) {
37:         if (!frame.options?.context?.member?.id) {
38:             throw new errors.UnauthorizedError({
39:                 message: tpl(messages.memberNotFound)
40:             });
41:         }
42:     }
43: 
44:     /**
45:      * Extract count.reports from filter string.
46:      * Returns the remaining filter, a reportCount option, and a mongoTransformer.
47:      *
48:      * @param {string} [filterString]
49:      * @returns {{filter: string|undefined, reportCount: {op: string, value: number}|undefined, mongoTransformer: Function|undefined}}
50:      */
51:     #extractReportCountFilter(filterString) {
52:         if (!filterString || !filterString.includes('count.reports')) {
53:             return {filter: filterString, reportCount: undefined, mongoTransformer: undefined};
54:         }
55: 
56:         const parsed = nql(filterString).parse();
57:         const [countReportsFilter, remainingFilter] = splitFilter(parsed, ['count.reports']);
58: 
59:         // Convert count.reports to reportCount option
60:         let reportCount;
61:         if (countReportsFilter?.['count.reports'] !== undefined) {
62:             const val = countReportsFilter['count.reports'];
63:             if (typeof val === 'number') {
64:                 reportCount = {op: '=', value: val};
65:             } else if (val.$gt !== undefined) {
66:                 reportCount = {op: '>', value: val.$gt};
67:             } else if (val.$gte !== undefined) {
68:                 reportCount = {op: '>=', value: val.$gte};
69:             } else if (val.$lt !== undefined) {
70:                 reportCount = {op: '<', value: val.$lt};
71:             } else if (val.$lte !== undefined) {
72:                 reportCount = {op: '<=', value: val.$lte};
73:             } else if (val.$ne !== undefined) {
74:                 reportCount = {op: '!=', value: val.$ne};
75:             }
76:         }
77: 
78:         // If there's remaining filter, use transformer to replace parsed result
79:         // Otherwise, no filter needed
80:         if (remainingFilter && Object.keys(remainingFilter).length > 0) {
81:             return {
82:                 filter: filterString, // Keep original string for NQL to parse
83:                 reportCount,
84:                 mongoTransformer: () => remainingFilter // Replace with our pre-split result
85:             };
86:         }
87: 
88:         return {filter: undefined, reportCount, mongoTransformer: undefined};
89:     }
90: 
91:     /**
92:      * @param {Frame} frame
93:      */
94:     async browse(frame) {
95:         if (frame.options.post_id) {
96:             if (frame.options.filter) {
97:                 frame.options.mongoTransformer = function (query) {
98:                     return {
99:                         $and: [
100:                             {
101:                                 post_id: frame.options.post_id
102:                             },
103:                             query
104:                         ]
105:                     };
106:                 };
107:             } else {
108:                 frame.options.filter = `post_id:${frame.options.post_id}`;
109:             }
110:         }
111: 
112:         return await this.service.getComments(frame.options);
113:     }
114: 
115:     async adminBrowse(frame) {
116:         if (frame.options.post_id) {
117:             if (frame.options.filter) {
118:                 frame.options.mongoTransformer = function (query) {
119:                     return {
120:                         $and: [
121:                             {
122:                                 post_id: frame.options.post_id
123:                             },
124:                             query
125:                         ]
126:                     };
127:                 };
128:             } else {
129:                 frame.options.filter = `post_id:${frame.options.post_id}`;
130:             }
131:         }
132: 
133:         frame.options.isAdmin = true;
134:         // Admin routes in Comments-UI lack member context due to cross-domain constraints (CORS), which prevents
135:         // credentials from being passed. This causes issues like the inability to determine if a
136:         // logged-in admin (acting on behalf of a member) has already liked a comment.
137:         // To resolve this, we retrieve the `impersonate_member_uuid` from the request params and
138:         // explicitly set it in the context options as the acting member's ID.
139:         // Note: This approach is applied to several admin routes where member context is required.
140:         await this.#setImpersonationContext(frame.options);
141:         return await this.service.getAdminComments(frame.options);
142:     }
143: 
144:     /**
145:      * Browse all comments across the site (admin only, no post_id required)
146:      * Used for admin moderation page showing comments from all posts
147:      *
148:      * Controller responsibility: Parse frame into clean domain parameters.
149:      * The frame should not pass beyond this layer.
150:      *
151:      * @param {Frame} frame
152:      */
153:     async adminBrowseAll(frame) {
154:         // Query params can be strings or booleans depending on how the request is made
155:         const includeNestedParam = frame.options.include_nested;
156:         const includeNested = includeNestedParam !== 'false' && includeNestedParam !== false;
157: 
158:         // Extract count.reports from filter (it needs special handling as raw SQL)
159:         const {filter, reportCount, mongoTransformer} = this.#extractReportCountFilter(frame.options.filter);
160: 
161:         return await this.service.getAdminAllComments({
162:             includeNested,
163:             filter,
164:             mongoTransformer,
165:             reportCount,
166:             order: frame.options.order || 'created_at desc',
167:             page: frame.options.page,
168:             limit: frame.options.limit
169:         });
170:     }
171: 
172:     /**
173:      * @param {Frame} frame
174:      */
175:     async replies(frame) {
176:         return this.service.getReplies(frame.options.id, _.omit(frame.options, 'id'));
177:     }
178: 
179:     /**
180:      * @param {Frame} frame
181:      */
182:     async adminReplies(frame) {
183:         frame.options.isAdmin = true;
184:         frame.options.order = 'created_at asc'; // we always want to load replies from oldest to newest
185:         await this.#setImpersonationContext(frame.options);
186: 
187:         return this.service.getReplies(frame.options.id, _.omit(frame.options, 'id'));
188:     }
189: 
190:     /**
191:      * @param {Frame} frame
192:      */
193:     async read(frame) {
194:         await this.#setImpersonationContext(frame.options);
195:         return await this.service.getCommentByID(frame.data.id, frame.options);
196:     }
197: 
198:     /**
199:      * @param {Frame} frame
200:      */
201:     async edit(frame) {
202:         this.#checkMember(frame);
203: 
204:         let result;
205:         if (frame.data.comments[0].status === 'deleted') {
206:             result = await this.service.deleteComment(
207:                 frame.options.id,
208:                 frame?.options?.context?.member?.id,
209:                 frame.options
210:             );
211:         } else {
212:             result = await this.service.editCommentContent(
213:                 frame.options.id,
214:                 frame?.options?.context?.member?.id,
215:                 frame.data.comments[0].html,
216:                 frame.options
217:             );
218:         }
219: 
220:         if (result) {
221:             const postId = result.get('post_id');
222:             const parentId = result.get('parent_id');
223:             const pathsToInvalidate = [
224:                 postId ? `/api/members/comments/post/${postId}/` : null,
225:                 parentId ? `/api/members/comments/${parentId}/replies/` : null
226:             ].filter(path => path !== null);
227:             frame.setHeader('X-Cache-Invalidate', pathsToInvalidate.join(', '));
228:         }
229: 
230:         return result;
231:     }
232: 
233:     /**
234:      * @param {Frame} frame
235:      */
236:     async add(frame) {
237:         this.#checkMember(frame);
238:         const data = frame.data.comments[0];
239: 
240:         let result;
241:         if (data.parent_id) {
242:             result = await this.service.replyToComment(
243:                 data.parent_id,
244:                 data.in_reply_to_id,
245:                 frame.options.context.member.id,
246:                 data.html,
247:                 frame.options
248:             );
249:         } else {
250:             result = await this.service.commentOnPost(
251:                 data.post_id,
252:                 frame.options.context.member.id,
253:                 data.html,
254:                 frame.options
255:             );
256:         }
257: 
258:         if (result) {
259:             const postId = result.get('post_id');
260:             const parentId = result.get('parent_id');
261:             const pathsToInvalidate = [
262:                 postId ? `/api/members/comments/post/${postId}/` : null,
263:                 parentId ? `/api/members/comments/${parentId}/replies/` : null
264:             ].filter(path => path !== null);
265:             frame.setHeader('X-Cache-Invalidate', pathsToInvalidate.join(', '));
266:         }
267: 
268:         return result;
269:     }
270: 
271:     async destroy() {
272:         throw new MethodNotAllowedError({
273:             message: tpl(messages.cannotDestroyComments)
274:         });
275:     }
276: 
277:     async count(frame) {
278:         if (!frame?.options?.ids) {
279:             return await this.stats.getAllCounts();
280:         }
281: 
282:         const ids = frame?.options?.ids.split(',');
283: 
284:         return await this.stats.getCountsByPost(ids);
285:     }
286: 
287:     /**
288:      * @param {Frame} frame
289:      */
290:     async like(frame) {
291:         this.#checkMember(frame);
292: 
293:         const result = await this.service.likeComment(
294:             frame.options.id,
295:             frame.options?.context?.member,
296:             frame.options
297:         );
298: 
299:         const comment = await this.service.getCommentByID(frame.options.id);
300: 
301:         if (comment) {
302:             const postId = comment.get('post_id');
303:             const parentId = comment.get('parent_id');
304:             const pathsToInvalidate = [
305:                 postId ? `/api/members/comments/post/${postId}/` : null,
306:                 parentId ? `/api/members/comments/${parentId}/replies/` : null
307:             ].filter(path => path !== null);
308:             frame.setHeader('X-Cache-Invalidate', pathsToInvalidate.join(', '));
309:         }
310: 
311:         return result;
312:     }
313: 
314:     /**
315:      * @param {Frame} frame
316:      */
317:     async unlike(frame) {
318:         this.#checkMember(frame);
319: 
320:         const result = await this.service.unlikeComment(
321:             frame.options.id,
322:             frame.options?.context?.member,
323:             frame.options
324:         );
325: 
326:         const comment = await this.service.getCommentByID(frame.options.id);
327: 
328:         if (comment) {
329:             const postId = comment.get('post_id');
330:             const parentId = comment.get('parent_id');
331:             const pathsToInvalidate = [
332:                 postId ? `/api/members/comments/post/${postId}/` : null,
333:                 parentId ? `/api/members/comments/${parentId}/replies/` : null
334:             ].filter(path => path !== null);
335:             frame.setHeader('X-Cache-Invalidate', pathsToInvalidate.join(', '));
336:         }
337: 
338:         return result;
339:     }
340: 
341:     /**
342:      * @param {Frame} frame
343:      */
344:     async report(frame) {
345:         this.#checkMember(frame);
346: 
347:         return await this.service.reportComment(
348:             frame.options.id,
349:             frame.options?.context?.member
350:         );
351:     }
352: 
353:     /**
354:      * Get reporters for a specific comment (admin only)
355:      * @param {Frame} frame
356:      */
357:     async getCommentReporters(frame) {
358:         const commentId = frame.options.id;
359:         return await this.service.getCommentReporters(commentId, {
360:             page: frame.options.page,
361:             limit: frame.options.limit
362:         });
363:     }
