37:     'id',
38:     'uuid',
39:     'title',
40:     'url',
41:     'feature_image'
42: ];
43: 
44: const countFields = [
45:     'replies',
46:     'likes'
47: ];
48: 
49: const countFieldsAdmin = [
50:     'replies',
51:     'likes',
52:     'reports'
53: ];
54: 
55: const commentMapper = (model, frame) => {
56:     const jsonModel = model.toJSON ? model.toJSON(frame.options) : model;
57: 
58:     const isPublicRequest = utils.isMembersAPI(frame);
59: 
60:     // For admin requests, we want to show a snippet for ALL replies
61:     // Use inReplyTo if available, otherwise fall back to parent for first-level replies
62:     const replyToComment = jsonModel.inReplyTo || (!isPublicRequest && jsonModel.parent_id && jsonModel.parent);
63: 
64:     if (replyToComment && (replyToComment.status === 'published' || (!isPublicRequest && replyToComment.status === 'hidden'))) {
65:         jsonModel.in_reply_to_snippet = htmlToPlaintext.commentSnippet(replyToComment.html);
66:     } else if (replyToComment && replyToComment.status !== 'published') {
67:         jsonModel.in_reply_to_snippet = '[removed]';
68:     } else {
69:         jsonModel.in_reply_to_snippet = null;
70:     }
71: 
72:     if (!jsonModel.inReplyTo) {
73:         jsonModel.in_reply_to_id = null;
74:     }
75: 
76:     const response = _.pick(jsonModel, commentFields);
77: 
78:     if (jsonModel.member) {
79:         response.member = _.pick(jsonModel.member, isPublicRequest ? memberFields : memberFieldsAdmin);
80:     } else {
81:         response.member = null;
82:     }
83: 
84:     if (jsonModel.replies) {
85:         response.replies = jsonModel.replies.map(reply => commentMapper(reply, frame));
86:     }
87: 
88:     if (jsonModel.parent) {
89:         response.parent = commentMapper(jsonModel.parent, frame);
90:     }
91: 
92:     if (jsonModel.post) {
93:         // We could use the post mapper here, but we need less field + don't need all the async behavior support
94:         url.forPost(jsonModel.post.id, jsonModel.post, frame);
95:         response.post = _.pick(jsonModel.post, postFields);
96: 
97:         // Compute excerpt from custom_excerpt or plaintext (same logic as post serializer)
98:         if (jsonModel.post.custom_excerpt) {
99:             response.post.excerpt = jsonModel.post.custom_excerpt;
100:         } else if (jsonModel.post.plaintext) {
101:             response.post.excerpt = jsonModel.post.plaintext.substring(0, 500);
102:         }
103:     }
104: 
105:     if (jsonModel.count && jsonModel.count.liked !== undefined) {
106:         response.liked = jsonModel.count.liked > 0;
107:     }
108: 
109:     if (jsonModel.count) {
110:         response.count = _.pick(jsonModel.count, isPublicRequest ? countFields : countFieldsAdmin);
111:     }
112: 
113:     if (isPublicRequest) {
114:         if (jsonModel.status !== 'published') {
115:             response.html = null;
116:         }
117:     }
118: 
119:     // Deleted comments should never expose their content
120:     if (jsonModel.status === 'deleted') {
121:         response.html = null;
122:     }
123: 
124:     return response;
125: };
126: 
127: module.exports = commentMapper;
